const e=JSON.parse('{"key":"v-11ded1ca","path":"/tech/java/spring/Spring%20%E8%8E%B7%E5%8F%96%E7%9C%9F%E5%AE%9EIp.html","title":"Spring 获取真实Ip","lang":"zh-CN","frontmatter":{"date":"2018-12-18T12:25:00.000Z","description":"Spring 获取真实Ip 获取客户端的IP地址的方法是：request.getRemoteAddr()，这种方法在大部分情况下都是有效的。 但是在通过了Apache,Squid等反向代理软件就不能获取到客户端的真实IP地址了，如果通过了多级反向代理的话，X-Forwarded-For的值并不止一个，而是一串IP值， 究竟哪个才是真正的用户端的真实IP呢？ 答案是取X-Forwarded-For中第一个非unknown的有效IP字符串。 例如：X-Forwarded-For：192.168.1.110, 192.168.1.120, 192.168.1.130, 192.168.1.100 用户真实IP为： 192.168.1.110","head":[["meta",{"property":"og:url","content":"https://dhbin.cn/tech/java/spring/Spring%20%E8%8E%B7%E5%8F%96%E7%9C%9F%E5%AE%9EIp.html"}],["meta",{"property":"og:site_name","content":"DHB"}],["meta",{"property":"og:title","content":"Spring 获取真实Ip"}],["meta",{"property":"og:description","content":"Spring 获取真实Ip 获取客户端的IP地址的方法是：request.getRemoteAddr()，这种方法在大部分情况下都是有效的。 但是在通过了Apache,Squid等反向代理软件就不能获取到客户端的真实IP地址了，如果通过了多级反向代理的话，X-Forwarded-For的值并不止一个，而是一串IP值， 究竟哪个才是真正的用户端的真实IP呢？ 答案是取X-Forwarded-For中第一个非unknown的有效IP字符串。 例如：X-Forwarded-For：192.168.1.110, 192.168.1.120, 192.168.1.130, 192.168.1.100 用户真实IP为： 192.168.1.110"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-21T07:43:00.000Z"}],["meta",{"property":"article:published_time","content":"2018-12-18T12:25:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-21T07:43:00.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Spring 获取真实Ip\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2018-12-18T12:25:00.000Z\\",\\"dateModified\\":\\"2023-03-21T07:43:00.000Z\\",\\"author\\":[]}"]]},"headers":[],"git":{"createdTime":1679384580000,"updatedTime":1679384580000,"contributors":[{"name":"donghaibin","email":"xx158@qq.com","commits":1}]},"readingTime":{"minutes":0.91,"words":274},"filePathRelative":"tech/java/spring/Spring 获取真实Ip.md","localizedDate":"2018年12月18日","excerpt":"<h1> Spring 获取真实Ip</h1>\\n<p>获取客户端的IP地址的方法是：request.getRemoteAddr()，这种方法在大部分情况下都是有效的。</p>\\n<p>但是在通过了Apache,Squid等反向代理软件就不能获取到客户端的真实IP地址了，如果通过了多级反向代理的话，X-Forwarded-For的值并不止一个，而是一串IP值， 究竟哪个才是真正的用户端的真实IP呢？</p>\\n<p>答案是取X-Forwarded-For中第一个非unknown的有效IP字符串。\\n例如：X-Forwarded-For：192.168.1.110, 192.168.1.120,\\n192.168.1.130, 192.168.1.100 用户真实IP为： 192.168.1.110</p>","autoDesc":true}');export{e as data};
